1	import { describe, it, expect, vi, beforeEach } from "vitest";
2	import { screen } from "@testing-library/react";
3	import { renderWithProviders } from "./helpers";
4	import Portfolio from "@/routes/Portfolio";
5	
6	// ---------------------------------------------------------------------------
7	// Mocks â€” hook-level, following codebase conventions
8	// ---------------------------------------------------------------------------
9	
10	vi.mock("@/features/session/context", async () => {
11	  const actual = await vi.importActual<typeof import("@/features/session/context")>(
12	    "@/features/session/context",
13	  );
14	  return {
15	    ...actual,
16	    useSession: vi.fn(),
17	  };
18	});
19	
20	vi.mock("@/lib/query/hooks", () => ({
21	  useAccountRisk: vi.fn(),
22	  useMarkets: vi.fn(),
23	}));
24	
25	import { useSession } from "@/features/session/context";
26	import { useAccountRisk, useMarkets } from "@/lib/query/hooks";
27	
28	const mockUseSession = vi.mocked(useSession);
29	const mockUseAccountRisk = vi.mocked(useAccountRisk);
30	const mockUseMarkets = vi.mocked(useMarkets);
31	
32	// ---------------------------------------------------------------------------
33	// Shared fixtures
34	// ---------------------------------------------------------------------------
35	
36	const unconfiguredSession = {
37	  session: { accountId: "", agentId: "" },
38	  setAccountId: vi.fn(),
39	  setAgentId: vi.fn(),
40	  isConfigured: false,
41	};
42	
43	const configuredSession = {
44	  session: { accountId: "acc-123", agentId: "agent-1" },
45	  setAccountId: vi.fn(),
46	  setAgentId: vi.fn(),
47	  isConfigured: true,
48	};
49	
50	const emptyQueryResult = {
51	  data: undefined,
52	  isLoading: false,
53	  error: null,
54	  isSuccess: false,
55	  isError: false,
56	  isPending: false,
57	  isLoadingError: false,
58	  isRefetchError: false,
59	  status: "pending" as const,
60	  fetchStatus: "idle" as const,
61	  isFetching: false,
62	  isPlaceholderData: false,
63	  isRefetching: false,
64	  isStale: false,
65	  dataUpdatedAt: 0,
66	  errorUpdatedAt: 0,
67	  failureCount: 0,
68	  failureReason: null,
69	  errorUpdateCount: 0,
70	  refetch: vi.fn(),
71	  promise: Promise.resolve(undefined as never),
72	};
73	
74	function makeRiskData(overrides: {
75	  status?: "healthy" | "warning" | "critical";
76	  markets?: Array<{
77	    marketId: string;
78	    minAsset: number;
79	    capacityConsumed: number;
80	    utilization: number;
81	    commandCount: number;
82	    lastOrderId: string;
83	    lastCommandId: string;
84	    updatedAt: string;
85	  }>;
86	  updatedAt?: string;
87	} = {}) {
88	  return {
89	    account: {
90	      id: "acc-123",
91	      risk: {
92	        minAssets: {
93	          overall: 42.5,
94	          markets: overrides.markets ?? [],
95	        },
96	        capacityIndicators: {
97	          limit: 1000.0,
98	          available: 750.25,
99	          consumed: 249.75,
100	          utilization: 0.24975,
101	          status: overrides.status ?? "healthy",
102	        },
103	        updatedAt: overrides.updatedAt ?? "2026-04-09T12:30:00Z",
104	      },
105	    },
106	    meta: { apiVersion: "1.0", timestamp: "2026-04-09T12:30:00Z" },
107	  };
108	}
109	
110	const defaultMarkets = {
111	  markets: [] as Array<{ id: string; title: string; status: string; liquidity: number; volume: number; expires_at: string }>,
112	  count: 0,
113	  meta: { apiVersion: "1.0", timestamp: "2026-04-09T00:00:00Z" },
114	};
115	
116	// ---------------------------------------------------------------------------
117	// Tests
118	// ---------------------------------------------------------------------------
119	
120	describe("Portfolio", () => {
121	  beforeEach(() => {
122	    vi.clearAllMocks();
123	    mockUseMarkets.mockReturnValue({ ...emptyQueryResult, data: defaultMarkets } as ReturnType<typeof useMarkets>);
124	  });
125	
126	  // -------------------------------------------------------------------------
127	  // Step 1 â€” Unconfigured session
128	  // -------------------------------------------------------------------------
129	  it("renders account prompt when no session configured", () => {
130	    mockUseSession.mockReturnValue(unconfiguredSession);
131	    mockUseAccountRisk.mockReturnValue({ ...emptyQueryResult } as ReturnType<typeof useAccountRisk>);
132	
133	    renderWithProviders(<Portfolio />);
134	    expect(screen.getByText(/Set your Account ID/)).toBeInTheDocument();
135	  });
136	
137	  // -------------------------------------------------------------------------
138	  // Step 2 â€” Loading state
139	  // -------------------------------------------------------------------------
140	  it("renders loading page while risk data loads", () => {
141	    mockUseSession.mockReturnValue(configuredSession);
142	    mockUseAccountRisk.mockReturnValue({
143	      ...emptyQueryResult,
144	      isLoading: true,
145	    } as ReturnType<typeof useAccountRisk>);
146	
147	    const { container } = renderWithProviders(<Portfolio />);
148	    // LoadingPage renders an SVG spinner
149	    expect(container.querySelector("svg")).toBeInTheDocument();
150	  });
151	
152	  // -------------------------------------------------------------------------
153	  // Step 3 â€” Error state
154	  // -------------------------------------------------------------------------
155	  it("renders error message when risk fetch fails", () => {
156	    mockUseSession.mockReturnValue(configuredSession);
157	    mockUseAccountRisk.mockReturnValue({
158	      ...emptyQueryResult,
159	      error: new Error("fail"),
160	    } as ReturnType<typeof useAccountRisk>);
161	
162	    renderWithProviders(<Portfolio />);
163	    expect(screen.getByText("Account not found or no positions yet.")).toBeInTheDocument();
164	  });
165	
166	  // -------------------------------------------------------------------------
167	  // Step 4 â€” Full data rendering (MetricCards)
168	  // -------------------------------------------------------------------------
169	  it("renders portfolio heading and metric cards with full data", () => {
170	    mockUseSession.mockReturnValue(configuredSession);
171	    mockUseAccountRisk.mockReturnValue({
172	      ...emptyQueryResult,
173	      data: makeRiskData(),
174	      isSuccess: true,
175	    } as ReturnType<typeof useAccountRisk>);
176	
177	    renderWithProviders(<Portfolio />);
178	
179	    expect(screen.getByText("Portfolio")).toBeInTheDocument();
180	    expect(screen.getByText("1000.00")).toBeInTheDocument(); // Limit
181	    expect(screen.getByText("750.25")).toBeInTheDocument(); // Available
182	    expect(screen.getByText("249.75")).toBeInTheDocument(); // Consumed
183	    expect(screen.getByText("25.0%")).toBeInTheDocument(); // Utilization
184	    expect(screen.getByText("healthy")).toBeInTheDocument(); // Health
185	    expect(screen.getByText("42.50")).toBeInTheDocument(); // Min Asset (Overall)
186	  });
187	
188	  // -------------------------------------------------------------------------
189	  // Step 5 â€” Health status colors
190	  // -------------------------------------------------------------------------
191	  it.each([
192	    { status: "healthy" as const, color: "var(--color-success)" },
193	    { status: "warning" as const, color: "var(--color-warning)" },
194	    { status: "critical" as const, color: "var(--color-danger)" },
195	  ])("renders health status '$status' with correct color", ({ status, color }) => {
196	    mockUseSession.mockReturnValue(configuredSession);
197	    mockUseAccountRisk.mockReturnValue({
198	      ...emptyQueryResult,
199	      data: makeRiskData({ status }),
200	      isSuccess: true,
201	    } as ReturnType<typeof useAccountRisk>);
202	
203	    renderWithProviders(<Portfolio />);
204	
205	    const healthValue = screen.getByText(status);
206	    expect(healthValue).toHaveStyle({ color });
207	  });
208	
209	  // -------------------------------------------------------------------------
210	  // Step 6 â€” Timestamp display
211	  // -------------------------------------------------------------------------
212	  it("renders last-updated timestamp", () => {
213	    const knownTimestamp = "2026-04-09T12:30:00Z";
214	    mockUseSession.mockReturnValue(configuredSession);
215	    mockUseAccountRisk.mockReturnValue({
216	      ...emptyQueryResult,
217	      data: makeRiskData({ updatedAt: knownTimestamp }),
218	      isSuccess: true,
219	    } as ReturnType<typeof useAccountRisk>);
220	
221	    renderWithProviders(<Portfolio />);
222	
223	    const expected = new Date(knownTimestamp).toLocaleString();
224	    expect(screen.getByText(`Last updated: ${expected}`)).toBeInTheDocument();
225	  });
226	
227	  // -------------------------------------------------------------------------
228	  // Step 7 â€” Per-market positions table
229	  // -------------------------------------------------------------------------
230	  it("renders per-market positions table with market links", () => {
231	    const marketRows = [
232	      {
233	        marketId: "mkt-1",
234	        minAsset: 15.5,
235	        capacityConsumed: 50,
236	        utilization: 0.123,
237	        commandCount: 7,
238	        lastOrderId: "ord-1",
239	        lastCommandId: "cmd-1",
240	        updatedAt: "2026-04-09T12:00:00Z",
241	      },
242	      {
243	        marketId: "mkt-2",
244	        minAsset: 27.0,
245	        capacityConsumed: 80,
246	        utilization: 0.456,
247	        commandCount: 3,
248	        lastOrderId: "ord-2",
249	        lastCommandId: "cmd-2",
250	        updatedAt: "2026-04-09T12:00:00Z",
251	      },
252	    ];
253	
254	    mockUseSession.mockReturnValue(configuredSession);
255	    mockUseAccountRisk.mockReturnValue({
256	      ...emptyQueryResult,
257	      data: makeRiskData({ markets: marketRows }),
258	      isSuccess: true,
259	    } as ReturnType<typeof useAccountRisk>);
260	    mockUseMarkets.mockReturnValue({
261	      ...emptyQueryResult,
262	      data: {
263	        markets: [
264	          { id: "mkt-1", title: "ETH Price > $3000", status: "active", liquidity: 100, volume: 200, expires_at: "2026-12-31T00:00:00Z" },
265	          { id: "mkt-2", title: "BTC Price > $100k", status: "active", liquidity: 500, volume: 1000, expires_at: "2026-12-31T00:00:00Z" },
266	        ],
267	        count: 2,
268	        meta: { apiVersion: "1.0", timestamp: "2026-04-09T00:00:00Z" },
269	      },
270	    } as ReturnType<typeof useMarkets>);
271	
272	    renderWithProviders(<Portfolio />);
273	
274	    // Table headers
275	    expect(screen.getByRole("columnheader", { name: "Market" })).toBeInTheDocument();
276	    expect(screen.getByRole("columnheader", { name: "Min Asset" })).toBeInTheDocument();
277	    expect(screen.getByRole("columnheader", { name: "Utilization" })).toBeInTheDocument();
278	    expect(screen.getByRole("columnheader", { name: "Trades" })).toBeInTheDocument();
279	
280	    // Market links with titles
281	    const ethLink = screen.getByText("ETH Price > $3000");
282	    expect(ethLink.closest("a")).toHaveAttribute("href", "/markets/mkt-1");
283	
284	    const btcLink = screen.getByText("BTC Price > $100k");
285	    expect(btcLink.closest("a")).toHaveAttribute("href", "/markets/mkt-2");
286	
287	    // Numeric values
288	    expect(screen.getByText("15.50")).toBeInTheDocument();
289	    expect(screen.getByText("27.00")).toBeInTheDocument();
290	    expect(screen.getByText("12.3%")).toBeInTheDocument();
291	    expect(screen.getByText("45.6%")).toBeInTheDocument();
292	    expect(screen.getByText("7")).toBeInTheDocument();
293	    expect(screen.getByText("3")).toBeInTheDocument();
294	  });
295	
296	  // -------------------------------------------------------------------------
297	  // Step 8 â€” Empty positions
298	  // -------------------------------------------------------------------------
299	  it("renders 'No positions.' when markets array is empty", () => {
300	    mockUseSession.mockReturnValue(configuredSession);
301	    mockUseAccountRisk.mockReturnValue({
302	      ...emptyQueryResult,
303	      data: makeRiskData({ markets: [] }),
304	      isSuccess: true,
305	    } as ReturnType<typeof useAccountRisk>);
306	
307	    renderWithProviders(<Portfolio />);
